import os
import shutil
from subprocess import run, PIPE

def backup_directory(source_dir, output_format):
    if not os.path.isdir(source_dir):
        print(f"Error: {source_dir} is not a valid directory.")
        return

    base_name = os.path.basename(source_dir)
    output_file = f"{base_name}.{output_format}"

    if output_format == 'tar.gz':
        run(['tar', '-czf', output_file, source_dir], check=True)
    elif output_format == 'tar.bz2':
        run(['tar', '-cjf', output_file, source_dir], check=True)
    elif output_format == 'zip':
        run(['zip', '-r', output_file, source_dir], check=True)
    elif output_format == '7z':
        run(['7z', 'a', output_file, source_dir], check=True)
    else:
        print(f"Error: Unsupported format {output_format}.")
        return

if __name__ == "__main__":
    import sys
    if len(sys.argv) != 3:
        print("Usage: python backup_script.py <directory_path> <format>")
        sys.exit(1)

    directory_path = sys.argv[1]
    format = sys.argv[2]

    backup_directory(directory_path, format)